class Solution:
    def checkInclusion(self, s1: str, s2: str) -> bool:
        s1_len = len(s1)
        s2_len = len(s2)
        if s2_len < s1_len:
            return False
        s1_count = {}
        for char in s1:
            if char not in s1_count:
                s1_count[char] = 0
            s1_count[char] += 1
        window_count = {}
        for i in range(s1_len):
            char = s2[i]
            if char not in window_count:
                window_count[char] = 0
            window_count[char] += 1
        if window_count == s1_count:
            return True
        for i in range(s1_len, s2_len):
            left_char = s2[i - s1_len]
            window_count[left_char] -= 1
            if window_count[left_char] == 0:
                del window_count[left_char]
            right_char = s2[i]
            if right_char not in window_count:
                window_count[right_char] = 0
            window_count[right_char] += 1
            if window_count == s1_count:
                return True
        return False
